    $(document).ready(function() {
        $('.tab').click(function() {
            var tabID = $(this).data('tabid');

            $('.buttons').children().removeClass('current');

            $(this).addClass('current');

            $('.wrapper').children().hide();
            $('.wrapper').find("[data-blockid=" + tabID + "]").show();
        });
    });
    </script>








